var s=context.state,a=context.action;
var PI2=Math.PI*2,PI=Math.PI;
var angDiff=function(x,y){var d=(x-y)%PI2;if(d>PI)d-=PI2;if(d<-PI)d+=PI2;return d;};
var myA=s.angle,toC=s.angleToCenter;
var myX=s.position.x,myY=s.position.y;
var dC=Math.sqrt((myX-450)*(myX-450)+(myY-450)*(myY-450));
var rem=context.round.remaining;
var closest=s.proximity[0]||{};
var front=s.scanner.robot[0]||false;
var progress=Math.max(0,1-rem/60);
var centerPull=progress*progress*0.6;
if(Math.random()<0.5) a.desiredForce=s.maxForce;
if(rem<5){
  if(dC>8){a.desiredAngle=toC;a.desiredForce=s.maxForce;}
  else a.desiredForce=0;
}else if(rem<12){
  a.desiredAngle=toC;a.desiredForce=s.maxForce;
  if(front&&front.active&&front.team!=s.team)a.desiredLaunch=true;
}else if(closest.entityType=="wall"){
  a.desiredAngle=toC;
}else if(front){
  if(front.active&&front.team!=s.team){
    a.desiredAngle=front.angleFromRobot;
    a.desiredLaunch=true;
  }else{
    var dir2=(front.angleFromRobot-myA)<0?-1:1;
    a.desiredAngle=myA-(dir2*0.174533);
    a.desiredForce=s.maxForce/2;
  }
}else{
  if(centerPull>0.05&&dC>120){
    a.desiredAngle=myA+angDiff(toC,myA)*centerPull;
  }
  if(Math.random()<0.005){
    var maxvar=PI/4;
    a.desiredAngle=myA+(Math.random()*maxvar)-maxvar/2;
    a.desiredForce=0;
  }
}
